<template>
  <div class="w-100 float-left" style="overflow: auto;" id="divNodeFlowChartNew">
    <input type="hidden" :value="showFromInvoice" />
    <input type="hidden" :value="showHistory" />
    <div v-if="flowData.length > 0"  style="width: 1805px; min-width: 1400px;">
      <RBillingFlowChart :data="flowData" chart-id="RflowChartNew" chart-class="outer" :isBillingType="isBillingType" />
    </div>
    <div v-else class="text-danger text-center" style="padding-top: 50%;">No Data Found</div>
  </div>
</template>

<script>
import RBillingFlowChart from '../../../views/BillingRule/ConfigurationComponent/RBillingFlowChart.vue';
import DataService from "../../../services/DataService";
export default {
  name: 'FlowChartWrapper',
  components: { RBillingFlowChart },
  props: {
    configurationId: {
      type: [String, Number],
      required: false
    },
    isBillingType :{
            type: Boolean,
            required: false
    }
  },
  data() {
    return {
      flowData: [],
      showHistory: 0,
      showFromInvoice: '1'
    };
  },
  created: async function () {
    var vm = this;
    if (vm.showFromInvoice === '1') {
      vm.fetchFlowData(vm.configurationId, vm.showHistory);
    }
  },
  methods: {
    fetchFlowData: async function (configurationId, showHistory = '0') {
      var vm = this;
      var params = "configId=" + configurationId + "&clientId=&includeParentNode=true&showHistory=" + showHistory;
      const response = await DataService.ShowFlowchartNew(params);
      if (response && response.data && response.data.length > 0) {
        this.flowData = response.data;
      }
    }
  }
};
</script>
<style scoped>

#RflowChartNew {
  width: unset !important;

}
</style>